import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {

  // ---------------------------------------------------------------
  // Configuration – adjust these knobs to change the generated data
  // ---------------------------------------------------------------
  const LOG_COUNT           = 50;   // total log lines to generate
  const BLOCK_RATIO         = 0.40; // ~40 % of traffic will be blocked
  const SERIAL_NUMBER       = '001801000001';
  const DEVICE_NAME         = 'PA-5260-LAB';
  const VSYS                = 'vsys1';
  const FIREWALL_VERSION    = '10.1.0';

  // Realistic network segments
  const INTERNAL_SUBNETS = [
    { net: '10.0.1',   zone: 'trust',      tag: 'Workstations' },
    { net: '10.0.2',   zone: 'trust',      tag: 'Servers' },
    { net: '10.0.10',  zone: 'dmz',        tag: 'DMZ-Servers' },
    { net: '172.16.5', zone: 'trust',      tag: 'VPN-Users' },
  ];

  const EXTERNAL_SUBNETS = [
    { net: '203.0.113', zone: 'untrust', tag: 'External' },
    { net: '198.51.100', zone: 'untrust', tag: 'External' },
    { net: '192.0.2',   zone: 'untrust', tag: 'External' },
  ];

  // Application / port / protocol combos
  const TRAFFIC_PROFILES = [
    { app: 'web-browsing',  dport: 80,   proto: 6,  risk: 1 },
    { app: 'ssl',           dport: 443,  proto: 6,  risk: 1 },
    { app: 'dns',           dport: 53,   proto: 17, risk: 1 },
    { app: 'ssh',           dport: 22,   proto: 6,  risk: 3 },
    { app: 'ftp',           dport: 21,   proto: 6,  risk: 4 },
    { app: 'smtp',          dport: 25,   proto: 6,  risk: 3 },
    { app: 'ms-sql-server', dport: 1433, proto: 6,  risk: 4 },
    { app: 'mysql',         dport: 3306, proto: 6,  risk: 4 },
    { app: 'rdp',           dport: 3389, proto: 6,  risk: 5 },
    { app: 'ntp',           dport: 123,  proto: 17, risk: 1 },
    { app: 'syslog',        dport: 514,  proto: 17, risk: 2 },
    { app: 'snmp',          dport: 161,  proto: 17, risk: 2 },
    { app: 'unknown-tcp',   dport: 4444, proto: 6,  risk: 5 },
    { app: 'unknown-tcp',   dport: 8080, proto: 6,  risk: 3 },
    { app: 'ping',          dport: 0,    proto: 1,  risk: 1 },
  ];

  // Security rules that will appear in the logs
  const ALLOW_RULES = [
    'Allow-Outbound-Web',
    'Allow-DNS',
    'Allow-Internal-SSH',
    'Allow-VPN-Access',
    'Allow-NTP',
    'Allow-DMZ-Inbound-HTTPS',
  ];

  const DENY_RULES = [
    'Deny-Inbound-RDP',
    'Deny-SQL-External',
    'Deny-FTP-External',
    'Block-Suspicious-Ports',
    'Deny-All-Default',
  ];

  // Rule-to-profile mapping: each rule only fires for realistic app/port combos
  const RULE_PROFILES = {
    'Deny-Inbound-RDP':        [{ app: 'rdp',           dport: 3389, proto: 6,  risk: 5 }],
    'Deny-SQL-External':       [{ app: 'ms-sql-server', dport: 1433, proto: 6,  risk: 4 },
                                { app: 'mysql',         dport: 3306, proto: 6,  risk: 4 }],
    'Deny-FTP-External':       [{ app: 'ftp',           dport: 21,   proto: 6,  risk: 4 }],
    'Block-Suspicious-Ports':  [{ app: 'unknown-tcp',   dport: 4444, proto: 6,  risk: 5 },
                                { app: 'unknown-tcp',   dport: 8080, proto: 6,  risk: 3 }],
    'Deny-All-Default':        TRAFFIC_PROFILES,
    'Allow-Outbound-Web':      [{ app: 'web-browsing',  dport: 80,   proto: 6,  risk: 1 },
                                { app: 'ssl',           dport: 443,  proto: 6,  risk: 1 }],
    'Allow-DNS':               [{ app: 'dns',           dport: 53,   proto: 17, risk: 1 }],
    'Allow-Internal-SSH':      [{ app: 'ssh',           dport: 22,   proto: 6,  risk: 3 }],
    'Allow-VPN-Access':        [{ app: 'web-browsing',  dport: 80,   proto: 6,  risk: 1 },
                                { app: 'ssl',           dport: 443,  proto: 6,  risk: 1 },
                                { app: 'dns',           dport: 53,   proto: 17, risk: 1 },
                                { app: 'ssh',           dport: 22,   proto: 6,  risk: 3 }],
    'Allow-NTP':               [{ app: 'ntp',           dport: 123,  proto: 17, risk: 1 }],
    'Allow-DMZ-Inbound-HTTPS': [{ app: 'ssl',           dport: 443,  proto: 6,  risk: 1 },
                                { app: 'web-browsing',  dport: 80,   proto: 6,  risk: 1 }],
  };

  // ---------------------------------------------------------------
  // Helpers
  // ---------------------------------------------------------------
  function randomInt(min, max) {
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }

  function pick(arr) {
    return arr[randomInt(0, arr.length - 1)];
  }

  function randomIp(subnet) {
    return `${subnet.net}.${randomInt(1, 254)}`;
  }

  function pad(n) { return n < 10 ? '0' + n : '' + n; }

  function generateTimestamp(index) {
    // Spread logs over the past hour
    const now = new Date();
    const offset = Math.floor((index / LOG_COUNT) * 3600 * 1000);
    const ts = new Date(now.getTime() - 3600000 + offset);
    return `${ts.getFullYear()}/${pad(ts.getMonth()+1)}/${pad(ts.getDate())} `
         + `${pad(ts.getHours())}:${pad(ts.getMinutes())}:${pad(ts.getSeconds())}`;
  }

  function generateSessionId() {
    return randomInt(100000, 999999);
  }

  // ---------------------------------------------------------------
  // Build a single PAN-OS 10.x traffic log line (CSV, ~70 fields)
  // Reference: https://docs.paloaltonetworks.com/pan-os/10-1/
  //   pan-os-admin/monitoring/use-syslog-for-monitoring/
  //   syslog-field-descriptions/traffic-log-fields
  // ---------------------------------------------------------------
  function buildLogLine(index) {
    const isBlocked = Math.random() < BLOCK_RATIO;
    const rule      = isBlocked ? pick(DENY_RULES) : pick(ALLOW_RULES);
    const profile   = pick(RULE_PROFILES[rule]);
    const action    = isBlocked
                        ? pick(['deny', 'drop', 'reset-both'])
                        : 'allow';

    // Direction: blocked traffic is mostly inbound
    let src, dst;
    if (isBlocked && Math.random() < 0.7) {
      src = pick(EXTERNAL_SUBNETS);
      dst = pick(INTERNAL_SUBNETS);
    } else {
      src = pick(INTERNAL_SUBNETS);
      dst = pick(EXTERNAL_SUBNETS);
    }

    const srcIp   = randomIp(src);
    const dstIp   = randomIp(dst);
    const srcPort = randomInt(1024, 65535);
    const dstPort = profile.dport;
    const proto   = profile.proto;

    const bytes_sent = isBlocked ? 0 : randomInt(200, 500000);
    const bytes_recv = isBlocked ? 0 : randomInt(200, 800000);
    const pkts_sent  = isBlocked ? randomInt(1, 3) : randomInt(5, 2000);
    const pkts_recv  = isBlocked ? 0 : randomInt(5, 3000);
    const elapsed    = isBlocked ? 0 : randomInt(1, 300);

    const sessionId = generateSessionId();
    const ts        = generateTimestamp(index);
    const repeatCnt = 1;

    const sessionEnd = isBlocked
      ? pick(['policy-deny', 'threat'])
      : pick(['tcp-fin', 'tcp-rst-from-client', 'tcp-rst-from-server', 'aged-out']);

    const category = isBlocked
      ? pick(['malware', 'command-and-control', 'hacking', 'any'])
      : pick(['general-internet', 'business-and-economy', 'computer-and-internet-info', 'any']);

    // PAN-OS 10.x traffic log CSV field order (simplified but faithful)
    // Fields are positional; unused fields are left empty or FUTURE_USE
    const fields = [
      /* 1  FUTURE_USE        */ '',
      /* 2  receive_time       */ ts,
      /* 3  serial             */ SERIAL_NUMBER,
      /* 4  type               */ 'TRAFFIC',
      /* 5  threat/content_type*/ 'end',
      /* 6  FUTURE_USE         */ '',
      /* 7  generated_time     */ ts,
      /* 8  src                */ srcIp,
      /* 9  dst                */ dstIp,
      /* 10 natsrc             */ srcIp,
      /* 11 natdst             */ dstIp,
      /* 12 rule               */ rule,
      /* 13 srcuser            */ src.tag === 'VPN-Users' ? 'vpn-user-' + randomInt(1,20) : '',
      /* 14 dstuser            */ '',
      /* 15 app                */ profile.app,
      /* 16 vsys               */ VSYS,
      /* 17 from               */ src.zone,
      /* 18 to                 */ dst.zone,
      /* 19 inbound_if         */ 'ethernet1/' + randomInt(1, 8),
      /* 20 outbound_if        */ 'ethernet1/' + randomInt(1, 8),
      /* 21 logset             */ 'default',
      /* 22 FUTURE_USE         */ '',
      /* 23 sessionid          */ sessionId,
      /* 24 repeatcnt          */ repeatCnt,
      /* 25 sport              */ srcPort,
      /* 26 dport              */ dstPort,
      /* 27 natsport           */ srcPort,
      /* 28 natdport           */ dstPort,
      /* 29 flags              */ '0x400000',
      /* 30 proto              */ proto,
      /* 31 action             */ action,
      /* 32 bytes              */ bytes_sent + bytes_recv,
      /* 33 bytes_sent         */ bytes_sent,
      /* 34 bytes_received     */ bytes_recv,
      /* 35 packets            */ pkts_sent + pkts_recv,
      /* 36 start              */ ts,
      /* 37 elapsed            */ elapsed,
      /* 38 category           */ category,
      /* 39 FUTURE_USE         */ '',
      /* 40 seqno              */ randomInt(1000000, 9999999),
      /* 41 actionflags        */ '0x8000000000000000',
      /* 42 srcloc             */ src.zone === 'untrust' ? 'US' : '',
      /* 43 dstloc             */ dst.zone === 'untrust' ? 'US' : '',
      /* 44 FUTURE_USE         */ '',
      /* 45 pkts_sent          */ pkts_sent,
      /* 46 pkts_received      */ pkts_recv,
      /* 47 session_end_reason */ sessionEnd,
      /* 48 dg_hier_level_1    */ 1,
      /* 49 dg_hier_level_2    */ 0,
      /* 50 dg_hier_level_3    */ 0,
      /* 51 dg_hier_level_4    */ 0,
      /* 52 vsys_name          */ VSYS,
      /* 53 device_name        */ DEVICE_NAME,
      /* 54 action_source      */ 'from-policy',
      /* 55 src_uuid           */ '',
      /* 56 dst_uuid           */ '',
      /* 57 tunnelid/imsi      */ 0,
      /* 58 monitortag/imei    */ '',
      /* 59 parent_session_id  */ 0,
      /* 60 parent_start_time  */ '',
      /* 61 tunnel             */ 0,
      /* 62 assoc_id           */ 0,
      /* 63 chunks             */ 0,
      /* 64 chunks_sent        */ 0,
      /* 65 chunks_received    */ 0,
      /* 66 rule_uuid          */ 'aaaaaaaa-bbbb-cccc-dddd-' + rule.replace(/[^a-zA-Z0-9]/g,'').substring(0,12).padEnd(12,'0'),
      /* 67 http2_connection   */ 0,
      /* 68 link_change_count  */ 0,
      /* 69 policy_id          */ randomInt(1, 200),
      /* 70 link_switches      */ '',
      /* 71 sdwan_cluster      */ '',
      /* 72 sdwan_device_type  */ '',
      /* 73 sdwan_cluster_type */ '',
      /* 74 sdwan_site         */ '',
      /* 75 dynusergroup_name  */ '',
      /* 76 xff_addr           */ '',
      /* 77 src_dvc_category   */ '',
      /* 78 src_dvc_profile    */ '',
      /* 79 src_dvc_model      */ '',
      /* 80 src_dvc_vendor     */ '',
      /* 81 src_dvc_os_family  */ '',
      /* 82 src_dvc_os_version */ '',
      /* 83 src_hostname       */ '',
      /* 84 src_mac            */ '',
      /* 85 dst_dvc_category   */ '',
      /* 86 dst_dvc_profile    */ '',
      /* 87 dst_dvc_model      */ '',
      /* 88 dst_dvc_vendor     */ '',
      /* 89 dst_dvc_os_family  */ '',
      /* 90 dst_dvc_os_version */ '',
      /* 91 dst_hostname       */ '',
      /* 92 dst_mac            */ '',
      /* 93 container_id       */ '',
      /* 94 pod_namespace      */ '',
      /* 95 pod_name           */ '',
      /* 96 src_edl           */ '',
      /* 97 dst_edl           */ '',
      /* 98 hostid            */ '',
      /* 99 serial_number     */ SERIAL_NUMBER,
      /* 100 src_dag           */ '',
      /* 101 dst_dag           */ '',
      /* 102 session_owner     */ '',
      /* 103 high_res_ts       */ ts,
    ];

    return fields.join(',');
  }

  // ---------------------------------------------------------------
  // Threat log builder (PAN-OS THREAT CSV format, simplified)
  // Covers: vulnerability, spyware, wildfire-virus, url, file subtypes
  // Reference: PAN-OS 10.x syslog threat log fields
  // ---------------------------------------------------------------
  const THREAT_TYPES = [
    { subtype: 'vulnerability', threatid: '30001', name: 'MS.Windows.SMB.Remote.Code.Execution', sev: 'critical', cat: 'code-execution' },
    { subtype: 'spyware',       threatid: '10002', name: 'Cobalt.Strike.C2.Beacon.Traffic',      sev: 'high',     cat: 'command-and-control' },
    { subtype: 'vulnerability', threatid: '30003', name: 'Log4j.JNDI.Remote.Code.Execution',     sev: 'critical', cat: 'code-execution' },
    { subtype: 'wildfire-virus',threatid: '20001', name: 'WildFire.Malware.Detected',            sev: 'high',     cat: 'malware' },
    { subtype: 'spyware',       threatid: '10003', name: 'DNS.C2.Beacon.Query',                  sev: 'medium',   cat: 'command-and-control' },
    { subtype: 'vulnerability', threatid: '30005', name: 'PHP.Remote.File.Inclusion',            sev: 'high',     cat: 'code-execution' },
    { subtype: 'url',           threatid: '46000', name: 'Phishing.URL.Detected',                sev: 'medium',   cat: 'phishing' },
    { subtype: 'file',          threatid: '52000', name: 'Suspicious.PE.File.Transferred',       sev: 'high',     cat: 'malware' },
    { subtype: 'vulnerability', threatid: '30010', name: 'SQL.Injection.Attack',                 sev: 'medium',   cat: 'sql-injection' },
    { subtype: 'vulnerability', threatid: '30011', name: 'RDP.BlueKeep.Exploit.Attempt',        sev: 'critical', cat: 'code-execution' },
  ];

  function buildThreatLogLine(index) {
    const threat  = pick(THREAT_TYPES);
    const srcSubnet = pick(EXTERNAL_SUBNETS);
    const dstSubnet = pick(INTERNAL_SUBNETS);
    const srcIp   = randomIp(srcSubnet);
    const dstIp   = randomIp(dstSubnet);
    const srcPort = randomInt(1024, 65535);
    const dstPort = pick([80, 443, 22, 445, 3389, 1433, 53]);
    const ts      = generateTimestamp(index);
    const sessionId = generateSessionId();
    const action  = pick(['block-ip', 'block', 'drop', 'reset-both', 'alert']);
    const seqno   = randomInt(1000000, 9999999);
    // Simplified PAN-OS THREAT log CSV (key fields only, others empty)
    const fields = [
      '',               // FUTURE_USE
      ts,               // receive_time
      SERIAL_NUMBER,    // serial
      'THREAT',         // type
      threat.subtype,   // threat/content_type
      '',               // FUTURE_USE
      ts,               // generated_time
      srcIp,            // src
      dstIp,            // dst
      srcIp,            // natsrc
      dstIp,            // natdst
      'Detect-and-Block', // rule
      '',               // srcuser
      '',               // dstuser
      'not-applicable', // app
      VSYS,             // vsys
      'untrust',        // from
      'trust',          // to
      'ethernet1/1',    // inbound_if
      'ethernet1/2',    // outbound_if
      'default',        // logset
      '',               // FUTURE_USE
      sessionId,        // sessionid
      1,                // repeatcnt
      srcPort,          // sport
      dstPort,          // dport
      srcPort,          // natsport
      dstPort,          // natdport
      '0x402000',       // flags
      6,                // proto (TCP)
      action,           // action
      threat.threatid,  // threatid
      threat.name,      // name
      threat.cat,       // category
      threat.sev,       // severity
      'default-vp',     // profile
      '',               // src_location
      '',               // dst_location
      '',               // FUTURE_USE
      seqno,            // seqno
      '0x8000000000000000', // actionflags
      'server-to-client',   // direction
      '', '', '',       // FUTURE_USE x3
      DEVICE_NAME,      // device_name
      VSYS,             // vsys_name
      '',               // src_uuid
      '',               // dst_uuid
    ];
    return fields.join(',');
  }

  // ---------------------------------------------------------------
  // System log builder (PAN-OS SYSTEM CSV format)
  // Covers: HA events, interface up/down, config commit, GP tunnel,
  //         login/logout, certificate expiry
  // ---------------------------------------------------------------
  const SYSTEM_EVENTS = [
    { subtype: 'ha',        sev: 'critical', eventid: 'ha_state_change',        description: 'HA peer is down; switching to active state' },
    { subtype: 'ha',        sev: 'high',     eventid: 'ha_peer_heartbeat_fail',  description: 'HA heartbeat failure detected' },
    { subtype: 'interface', sev: 'high',     eventid: 'if_state_down',           description: 'Interface ethernet1/1 went down' },
    { subtype: 'interface', sev: 'medium',   eventid: 'if_state_up',             description: 'Interface ethernet1/1 came back up' },
    { subtype: 'general',   sev: 'informational', eventid: 'config_committed',   description: 'Configuration committed successfully by admin' },
    { subtype: 'globalprotect', sev: 'informational', eventid: 'gp_tunnel_connected', description: 'GlobalProtect gateway tunnel established for user vpn-user' },
    { subtype: 'globalprotect', sev: 'medium', eventid: 'gp_auth_failure',       description: 'GlobalProtect authentication failed for user vpn-user' },
    { subtype: 'login',     sev: 'informational', eventid: 'admin_login',        description: 'Admin admin logged in from 10.0.1.50 via web' },
    { subtype: 'login',     sev: 'medium',   eventid: 'admin_login_failed',      description: 'Failed login attempt for admin from 203.0.113.10' },
    { subtype: 'general',   sev: 'medium',   eventid: 'cert_expiring',           description: 'Certificate SSL-CertProfile expires in 30 days' },
    { subtype: 'routing',   sev: 'high',     eventid: 'bgp_peer_down',           description: 'BGP peer 203.0.113.1 went down' },
    { subtype: 'dnsproxy',  sev: 'informational', eventid: 'dns_proxy_started',  description: 'DNS proxy started on vsys1' },
  ];

  function buildSystemLogLine(index) {
    const ev  = pick(SYSTEM_EVENTS);
    const ts  = generateTimestamp(index);
    const seqno = randomInt(1000000, 9999999);
    const fields = [
      '',           // FUTURE_USE
      ts,           // receive_time
      SERIAL_NUMBER,// serial
      'SYSTEM',     // type
      ev.subtype,   // threat/content_type (subtype for system logs)
      '',           // FUTURE_USE
      ts,           // generated_time
      '',           // vsys (empty for system logs)
      ev.eventid,   // eventid
      ev.description, // object
      '',           // fmt (module)
      '',           // id
      ev.sev,       // severity
      seqno,        // seqno
      DEVICE_NAME,  // device_name
      VSYS,         // vsys_name
    ];
    return fields.join(',');
  }

  // ---------------------------------------------------------------
  // Config/Audit log builder (PAN-OS CONFIG CSV format)
  // Covers: admin config changes, commit operations, object edits
  // ---------------------------------------------------------------
  const CONFIG_ACTIONS = [
    { cmd: 'set',    path: 'security rules name "Allow-Outbound-Web"', result: 'Succeeded' },
    { cmd: 'set',    path: 'address name "Internal-Server-New"',        result: 'Succeeded' },
    { cmd: 'delete', path: 'security rules name "Old-Rule"',            result: 'Succeeded' },
    { cmd: 'commit', path: '',                                           result: 'Succeeded' },
    { cmd: 'set',    path: 'zone name "dmz" network layer3 ethernet1/3', result: 'Succeeded' },
    { cmd: 'set',    path: 'threat-exception name "TE-SQL" rules action allow', result: 'Succeeded' },
    { cmd: 'commit', path: '',                                           result: 'Failed - Config validation error' },
    { cmd: 'set',    path: 'admin-role name "ReadOnly"',                result: 'Succeeded' },
    { cmd: 'set',    path: 'log-forwarding-profile name "Syslog-Profile"', result: 'Succeeded' },
  ];
  const ADMIN_USERS = ['admin', 'netops-alice', 'secops-bob', 'readonly-carol'];
  const ADMIN_HOSTS = ['10.0.1.50', '10.0.1.51', '10.0.2.20', '172.16.5.100'];

  function buildConfigLogLine(index) {
    const action = pick(CONFIG_ACTIONS);
    const admin  = pick(ADMIN_USERS);
    const host   = pick(ADMIN_HOSTS);
    const ts     = generateTimestamp(index);
    const seqno  = randomInt(1000000, 9999999);
    const fields = [
      '',           // FUTURE_USE
      ts,           // receive_time
      SERIAL_NUMBER,// serial
      'CONFIG',     // type
      '',           // threat/content_type
      '',           // FUTURE_USE
      ts,           // generated_time
      host,         // host
      VSYS,         // vsys
      admin,        // admin
      'Web',        // client (Web/CLI/XML API)
      action.result,// result
      action.cmd,   // type (set/delete/commit)
      action.path,  // path
      seqno,        // seqno
      DEVICE_NAME,  // device_name
    ];
    return fields.join(',');
  }

  // ---------------------------------------------------------------
  // Generate all log lines across all 4 log types
  // Distribution: 60% TRAFFIC, 20% THREAT, 12% SYSTEM, 8% CONFIG
  // ---------------------------------------------------------------
  const logLines   = [];
  const threatLines = [];
  const systemLines = [];
  const configLines = [];
  const summary  = {
    total: LOG_COUNT,
    allowed: 0, blocked: 0,
    byLogType: { TRAFFIC: 0, THREAT: 0, SYSTEM: 0, CONFIG: 0 },
    byAction: {}, byApp: {},
  };

  for (let i = 0; i < LOG_COUNT; i++) {
    const roll = Math.random();
    if (roll < 0.60) {
      const line = buildLogLine(i);
      logLines.push(line);
      summary.byLogType.TRAFFIC++;
      const parts  = line.split(',');
      const action = parts[30];
      const app    = parts[14];
      summary.byAction[action] = (summary.byAction[action] || 0) + 1;
      summary.byApp[app]       = (summary.byApp[app] || 0) + 1;
      if (action === 'allow') { summary.allowed++; } else { summary.blocked++; }
    } else if (roll < 0.80) {
      const line = buildThreatLogLine(i);
      threatLines.push(line);
      summary.byLogType.THREAT++;
    } else if (roll < 0.92) {
      const line = buildSystemLogLine(i);
      systemLines.push(line);
      summary.byLogType.SYSTEM++;
    } else {
      const line = buildConfigLogLine(i);
      configLines.push(line);
      summary.byLogType.CONFIG++;
    }
  }

  const allLines = [...logLines, ...threatLines, ...systemLines, ...configLines];

  console.log(`Generated ${allLines.length} Palo Alto log entries.`);
  console.log(`  By type: ${JSON.stringify(summary.byLogType)}`);
  console.log(`  Traffic allowed: ${summary.allowed}, blocked: ${summary.blocked}`);

  return {
    logLines:     logLines,
    threatLines:  threatLines,
    systemLines:  systemLines,
    configLines:  configLines,
    allLines:     allLines,
    summary:      summary,
  };
}

import { execution } from '@dynatrace-sdk/automation-utils';
import { logsClient } from '@dynatrace-sdk/client-classic-environment-v2';

const BATCH_SIZE = 20;

export default async function ({ execution_id }) {
  const ex = await execution();
  const genResult = await ex.result('generate_palo_alto_logs');
  const { logLines, threatLines, systemLines, configLines, summary } = genResult;

  const logEntries = [];

  // --- TRAFFIC logs ---
  for (const line of logLines) {
    const f = line.split(',');
    if (f.length < 50) continue;
    logEntries.push({
      'content':                    line,
      'log.source':                 'palo-alto-firewall',
      'log.tag':                    'demo-log-generator',
      'severity':                   f[30] === 'allow' ? 'INFO' : 'WARN',
      'source_vendor':              'Palo Alto',
      'source_product':             'PAN-OS',
      'env':                        'demo',
      'hostname':                   f[52] || 'PA-5260-LAB',
      'paloalto.type':              'TRAFFIC',
      'paloalto.serial':            f[2],
      'paloalto.src':               f[7],
      'paloalto.dst':               f[8],
      'paloalto.rule':              f[11],
      'paloalto.app':               f[14],
      'paloalto.from_zone':         f[16],
      'paloalto.to_zone':           f[17],
      'paloalto.action':            f[30],
      'paloalto.bytes_sent':        parseInt(f[32]) || 0,
      'paloalto.bytes_received':    parseInt(f[33]) || 0,
      'paloalto.session_end_reason': f[46],
      'paloalto.device_name':       f[52],
      'paloalto.dport':             parseInt(f[25]) || 0,
      'paloalto.sport':             parseInt(f[24]) || 0,
      'paloalto.proto':             parseInt(f[29]) || 0,
    });
  }

  // --- THREAT logs ---
  for (const line of threatLines) {
    const f = line.split(',');
    if (f.length < 20) continue;
    const sev = f[33]; // severity field
    const sevMap = { critical: 'ERROR', high: 'ERROR', medium: 'WARN', low: 'INFO', informational: 'INFO' };
    logEntries.push({
      'content':              line,
      'log.source':           'palo-alto-firewall',
      'log.tag':              'demo-log-generator',
      'severity':             sevMap[sev] || 'WARN',
      'source_vendor':        'Palo Alto',
      'source_product':       'PAN-OS',
      'env':                  'demo',
      'hostname':             'PA-5260-LAB',
      'paloalto.type':        'THREAT',
      'paloalto.subtype':     f[4],
      'paloalto.serial':      f[2],
      'paloalto.src':         f[7],
      'paloalto.dst':         f[8],
      'paloalto.rule':        f[11],
      'paloalto.from_zone':   f[15],
      'paloalto.to_zone':     f[16],
      'paloalto.action':      f[30],
      'paloalto.threat_id':   f[31],
      'paloalto.threat_name': f[32],
      'paloalto.threat_category': f[33],
      'paloalto.severity':    f[34],
      'paloalto.dport':       parseInt(f[25]) || 0,
      'paloalto.sport':       parseInt(f[24]) || 0,
    });
  }

  // --- SYSTEM logs ---
  for (const line of systemLines) {
    const f = line.split(',');
    if (f.length < 10) continue;
    const sev = f[12]; // severity field in system logs
    const sevMap = { critical: 'ERROR', high: 'ERROR', medium: 'WARN', low: 'INFO', informational: 'INFO' };
    logEntries.push({
      'content':              line,
      'log.source':           'palo-alto-firewall',
      'log.tag':              'demo-log-generator',
      'severity':             sevMap[sev] || 'INFO',
      'source_vendor':        'Palo Alto',
      'source_product':       'PAN-OS',
      'env':                  'demo',
      'hostname':             f[14] || 'PA-5260-LAB',
      'paloalto.type':        'SYSTEM',
      'paloalto.subtype':     f[4],
      'paloalto.serial':      f[2],
      'paloalto.event_id':    f[8],
      'paloalto.description': f[9],
      'paloalto.severity':    sev,
      'paloalto.device_name': f[14],
    });
  }

  // --- CONFIG logs ---
  for (const line of configLines) {
    const f = line.split(',');
    if (f.length < 12) continue;
    logEntries.push({
      'content':                line,
      'log.source':             'palo-alto-firewall',
      'log.tag':                'demo-log-generator',
      'severity':               f[11].toLowerCase().includes('fail') ? 'WARN' : 'INFO',
      'source_vendor':          'Palo Alto',
      'source_product':         'PAN-OS',
      'env':                    'demo',
      'hostname':               f[15] || 'PA-5260-LAB',
      'paloalto.type':          'CONFIG',
      'paloalto.serial':        f[2],
      'paloalto.admin':         f[9],
      'paloalto.client':        f[10],
      'paloalto.result':        f[11],
      'paloalto.config_cmd':    f[12],
      'paloalto.config_path':   f[13],
      'paloalto.device_name':   f[15],
    });
  }

  let ingested = 0;
  const errors = [];
  for (let i = 0; i < logEntries.length; i += BATCH_SIZE) {
    const batch = logEntries.slice(i, i + BATCH_SIZE);
    try {
      await logsClient.storeLog({
        type: 'application/json; charset=utf-8',
        body: batch,
      });
      ingested += batch.length;
      console.log(`Batch ${Math.floor(i/BATCH_SIZE)+1}: ingested ${batch.length} entries.`);
    } catch (e) {
      const msg = `Batch ${Math.floor(i/BATCH_SIZE)+1} failed: ${e.message}`;
      console.error(msg);
      errors.push(msg);
    }
  }

  console.log(`Ingested ${ingested}/${logEntries.length} log entries into Grail.`);
  return {
    totalIngested: ingested,
    totalAttempted: logEntries.length,
    byLogType: summary.byLogType,
    errors: errors,
  };
}

import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const ex = await execution();
  const genResult = await ex.result('generate_palo_alto_logs');
  const { logLines, threatLines, systemLines, configLines, summary } = genResult;

  const blockedEntries = [];
  const allowedEntries = [];

  for (const line of logLines) {
    if (line.startsWith('#')) continue;
    const f = line.split(',');
    if (f.length < 50) continue;
    const entry = {
      timestamp: f[1], src: f[7], dst: f[8],
      rule: f[11], app: f[14], fromZone: f[16], toZone: f[17],
      action: f[30], bytesSent: parseInt(f[32]) || 0,
      bytesRecv: parseInt(f[33]) || 0, sessionEnd: f[46], deviceName: f[52],
    };
    if (entry.action === 'allow') { allowedEntries.push(entry); }
    else { blockedEntries.push(entry); }
  }
  const byRule = {};
  for (const e of blockedEntries) {
    if (!byRule[e.rule]) byRule[e.rule] = { count: 0, apps: new Set(), sources: new Set() };
    byRule[e.rule].count++;
    byRule[e.rule].apps.add(e.app);
    byRule[e.rule].sources.add(e.src);
  }
  const ruleBreakdown = {};
  for (const [rule, data] of Object.entries(byRule)) {
    ruleBreakdown[rule] = { count: data.count, apps: [...data.apps], sources: [...data.sources].slice(0, 10) };
  }

  // Threat analysis
  const threatBySev = {};
  const threatByType = {};
  for (const line of threatLines) {
    const f = line.split(',');
    const subtype = f[4] || 'unknown';
    const sev = f[34] || 'unknown';
    threatBySev[sev]      = (threatBySev[sev] || 0) + 1;
    threatByType[subtype] = (threatByType[subtype] || 0) + 1;
  }

  // System analysis
  const systemBySubtype = {};
  for (const line of systemLines) {
    const f = line.split(',');
    const subtype = f[4] || 'unknown';
    systemBySubtype[subtype] = (systemBySubtype[subtype] || 0) + 1;
  }

  // Config analysis
  const configByCmd    = {};
  const configByResult = {};
  for (const line of configLines) {
    const f = line.split(',');
    const cmd    = f[12] || 'unknown';
    const result = f[11] || 'unknown';
    configByCmd[cmd]       = (configByCmd[cmd] || 0) + 1;
    configByResult[result] = (configByResult[result] || 0) + 1;
  }

  const report = {
    totalEntries:     (logLines.length + threatLines.length + systemLines.length + configLines.length),
    byLogType:        summary.byLogType,
    trafficAllowed:   allowedEntries.length,
    trafficBlocked:   blockedEntries.length,
    blockedByRule:    ruleBreakdown,
    threatBySeverity: threatBySev,
    threatBySubtype:  threatByType,
    systemBySubtype:  systemBySubtype,
    configByCmd:      configByCmd,
    configByResult:   configByResult,
    validationResult: (threatLines.length > 0 && systemLines.length > 0 && configLines.length > 0)
      ? `PASS - All 4 log types present: Traffic:${logLines.length} Threat:${threatLines.length} System:${systemLines.length} Config:${configLines.length}`
      : 'PARTIAL - Some log types missing',
  };

  console.log(`Analysis: ${report.validationResult}`);
  return report;
}
